import env from '../env.ts'
import { encode } from 'std/encoding/base64.ts'
import { Purchases } from '../types/route-types.ts'
import { Tables } from '../types/db-types.ts'
import {
  escapeHtml,
  formatCents,
  objectEntries,
  purchaseBreakdown,
  totalCost,
} from './misc.ts'
import { PASSWORD_RESET_SECRET_KEY } from './constants.ts'
import { withDBConnection } from './db.ts'

const MAILGUN_DOMAIN = 'mail.vibe.camp'
const FROM = `Vibecamp <support@${MAILGUN_DOMAIN}>`
const REPLY_TO = 'support@vibe.camp'

export type Email = {
  readonly to: string
  readonly subject: string
  readonly html: string
}

export async function sendMail(email: Email) {
  const allFields = [
    ...objectEntries(email),
    ['from', FROM],
    ['h:Reply-To', REPLY_TO],
  ] as const

  const opts = {
    method: 'post',
    body: allFields
      .map(([key, value]) => `${key}=${encodeURIComponent(value)}`)
      .join('&'),
    headers: {
      'Content-Type': 'application/x-www-form-urlencoded',
      'Authorization': `Basic ${encode('api:' + env.MAILGUN_API_KEY)}`,
    },
  }

  if (!env.MAILGUN_API_KEY) {
    console.warn("MAILGUN_API_KEY is unset in the environment, so this email wasn't sent:\n", JSON.stringify(opts, null, 2))
    return
  }

  const res = await fetch(
    `https://api.mailgun.net/v3/${MAILGUN_DOMAIN}/messages`,
    opts,
  )

  if (!res.ok) {
    const { html: _, ...rest } = email
    throw Error(`Failed to send mailgun email: ${JSON.stringify(rest)}`)
  }
}

const DEFAULT_BANNER_IMAGE = 'data:image/png;base64,'

export const receiptEmail = async (
  account: Pick<Tables['account'], 'email_address' | 'account_id'>,
  purchases: Purchases,
  discounts: readonly Tables['discount'][],
  { isGift }: { isGift?: boolean } = {},
): Promise<Email> => {
  const allPurchaseTypes = await withDBConnection((db) =>
    db.queryTable('purchase_type')
  )
  const allFestivals = await withDBConnection((db) => db.queryTable('festival'))

  const purchaseTypes = objectEntries(purchases)
    .filter(([_, count]) => count != null && count > 0)
    .map(([type, _]) =>
      allPurchaseTypes.find((p) => p.purchase_type_id === type)
    )
  const festival = allFestivals.find((f) =>
    f.festival_id === purchaseTypes[0]?.festival_id
  )
  const now = new Date()

  const purchasesInfo = purchaseBreakdown(
    purchases,
    discounts,
    allPurchaseTypes,
  )
  const total = totalCost(purchasesInfo)

  const purchaseRows = purchasesInfo.map((
    { purchaseType, count, basePrice, discountMultiplier, discountedPrice },
  ) =>
    `<tr>
            <td>${purchaseType.description} x${count}</td>
            <td>
                ${discountMultiplier != null
      ? `<s>$${formatCents(basePrice)}</s> $${formatCents(discountedPrice)}`
      : `$${formatCents(basePrice)}`
    }
            </td>
        </tr>`
  )
    .join('\n')

  const bannerImage = festival?.email_banner_image || DEFAULT_BANNER_IMAGE

  const heading = isGift
    ? `Someone is going to ${festival?.festival_name} thanks to you!`
    : `You're going to ${festival?.festival_name}!`

  const intro = isGift
    ? `This email is your receipt for the gift you purchased. The recipient will receive their own email with instructions to claim it.`
    : `This email is your receipt for your purchases. You can visit
                    <a href="${env.FRONT_END_BASE_URL}">my.vibe.camp</a> to view your
                    tickets or purchase anything else you need. The app will also
                    be updated as the festival approaches with things like an event
                    schedule, a site map, and more, so be sure to check back!`

  return {
    to: account.email_address,
    subject: isGift ? 'Vibecamp gift purchase receipt' : 'Vibecamp purchase receipt',
    html: withContainer(`
            <img src="${bannerImage}">

            <div class="container">
                <h1>${heading}</h1>
                <p>${intro}</p>
                <h2>Purchases:</h2>
                <table>
                    ${purchaseRows}

                    ${discounts.length > 0
        ? `<tr>
                            <td>Discount code:</td>
                            <td>${discounts[0]!.discount_code}</td>
                        </tr>`
        : ''
      }

                    <tr>
                        <td>Total:</td>
                        <td>$${formatCents(total)}</td>
                    </tr>
                </table>
                <p class="details">
                    Purchased on ${now.toDateString()} ${now.toTimeString()}
                </p>
                <p class="details">
                    Account ID: ${account.account_id}
                </p>
            </div>
        `),
  }
}

export const avNeedsEmail = (
  event: Pick<Tables['event'], 'name' | 'description' | 'start_datetime' | 'end_datetime' | 'av_needs'>,
  creator: { name: string | null, email_address: string },
  eventSiteName: string | null,
): Email => {
  const fmtDate = (d: Date | null) =>
    d == null ? '(none)' : new Date(d).toUTCString()

  return {
    to: env.AV_NEEDS_EMAIL,
    subject: `New A/V request: ${event.name}`,
    html: withContainer(`
            <div class="container">
                <h1>New A/V request</h1>
                <h2>${escapeHtml(event.name)}</h2>
                <p><b>Host:</b> ${escapeHtml(creator.name ?? '(unnamed)')} &lt;${escapeHtml(creator.email_address)}&gt;</p>
                <p><b>Site:</b> ${escapeHtml(eventSiteName ?? '(unknown)')}</p>
                <p><b>Start:</b> ${escapeHtml(fmtDate(event.start_datetime))}</p>
                <p><b>End:</b> ${escapeHtml(fmtDate(event.end_datetime))}</p>
                <h3>Event description</h3>
                <p>${escapeHtml(event.description).replaceAll('\n', '<br>')}</p>
                <h3>A/V needs</h3>
                <p>${escapeHtml(event.av_needs ?? '').replaceAll('\n', '<br>')}</p>
            </div>
        `),
  }
}

export const giftEmail = async (
  recipient: Pick<Tables['account'], 'email_address' | 'account_id'>,
  purchaserName: string,
  purchases: Purchases,
  passwordResetSecret?: string,
): Promise<Email> => {
  const allPurchaseTypes = await withDBConnection((db) =>
    db.queryTable('purchase_type')
  )
  const allFestivals = await withDBConnection((db) => db.queryTable('festival'))

  const purchaseTypes = objectEntries(purchases)
    .filter(([_, count]) => count != null && count > 0)
    .map(([type, _]) =>
      allPurchaseTypes.find((p) => p.purchase_type_id === type)
    )
  const festival = allFestivals.find((f) =>
    f.festival_id === purchaseTypes[0]?.festival_id
  )

  const items = objectEntries(purchases)
    .filter(([_, count]) => count != null && count > 0)
    .map(([typeId, count]) => {
      const type = allPurchaseTypes.find((p) => p.purchase_type_id === typeId)
      return type
        ? `<li>${escapeHtml(type.description)} &times; ${count}</li>`
        : ''
    })
    .join('\n')

  const bannerImage = festival?.email_banner_image || DEFAULT_BANNER_IMAGE

  const ctaUrl = passwordResetSecret != null
    ? `${env.FRONT_END_BASE_URL}#${encodeURIComponent(JSON.stringify({ [PASSWORD_RESET_SECRET_KEY]: passwordResetSecret }))
    }`
    : env.FRONT_END_BASE_URL

  const ctaLabel = passwordResetSecret != null
    ? 'Set up your account'
    : 'Sign in to view your gift'

  const intro = passwordResetSecret != null
    ? `We've created an account for you at this email address. Click the link below to set a password and finish setting up your account.`
    : `Sign in to my.vibe.camp to view it.`

  return {
    to: recipient.email_address,
    subject: 'You\'ve been gifted a Vibecamp ticket!',
    html: withContainer(`
            <img src="${bannerImage}">

            <div class="container">
                <h1>${escapeHtml(purchaserName)} bought you a Vibecamp ticket!</h1>

                <ul>
                    ${items}
                </ul>
              
                <p>${intro}</p>

                <a class="cta" href="${ctaUrl}">${ctaLabel}</a>
            </div>
        `),
  }
}

export const passwordResetEmail = (
  account: Pick<Tables['account'], 'email_address' | 'account_id'>,
  secret: string,
): Email => {
  const resetUrl = `${env.FRONT_END_BASE_URL}#${encodeURIComponent(JSON.stringify({ [PASSWORD_RESET_SECRET_KEY]: secret }))
    }`

  return {
    to: account.email_address,
    subject: 'Vibecamp password reset',
    html: withContainer(`
            <div class="container">
                <h1>Vibecamp password reset</h1>
                <p>
                    You've requested that your account password be reset. <b>
                    Nothing has happened yet</b>, you can click the link below
                    to set a new password on your my.vibe.camp account.
                </p>
                <p>
                    <a href=${resetUrl}>
                        ${resetUrl}
                    </a>
                </p>
                <p class="details">
                    Account ID: ${account.account_id}
                </p>
            </div>
        `),
  }
}

